const crypto = require('crypto');

// Get binary data from the uploaded file
const binaryData = $binary.data;
const buffer = Buffer.from(binaryData.data, 'base64');

// Calculate SHA-256 hash of file content
const hash = crypto.createHash('sha256').update(buffer).digest('hex');

// Generate UUID for document_id
const documentId = crypto.randomUUID();

// Extract file metadata
const fileName = binaryData.fileName || 'unknown';
const fileSize = buffer.length;
const mimeType = binaryData.mimeType || 'application/octet-stream';

// Get current timestamp
const uploadedAt = new Date().toISOString();

// Determine source (form or webhook)
const source = $node.name.includes('Form') ? 'form' : 'webhook';

// Return metadata and preserve binary data
return {
  json: {
    document_id: documentId,
    file_name: fileName,
    file_size: fileSize,
    mime_type: mimeType,
    file_hash: hash,
    uploaded_at: uploadedAt,
    source: source
  },
  binary: {
    data: binaryData
  }
};
